import React, { useEffect, useState } from "react";
import { getDatabase, ref, onValue } from "firebase/database";

function App() {
  const [leftFootData, setLeftFootData] = useState([]);
  const [rightFootData, setRightFootData] = useState([]);

  useEffect(() => {
    const db = getDatabase();

    const leftRef = ref(db, "leftFoot");
    const rightRef = ref(db, "rightFoot");

    const unsubscribeLeft = onValue(leftRef, (snapshot) => {
      const data = snapshot.val();
      if (data) {
        const entries = Object.values(data);
        setLeftFootData(entries);
      } else {
        setLeftFootData([]);
      }
    });

    const unsubscribeRight = onValue(rightRef, (snapshot) => {
      const data = snapshot.val();
      if (data) {
        const entries = Object.values(data);
        setRightFootData(entries);
      } else {
        setRightFootData([]);
      }
    });

    return () => {
      unsubscribeLeft();
      unsubscribeRight();
    };
  }, []);

  // Prepare maximum number of rows to show
  const maxRows = Math.max(leftFootData.length, rightFootData.length);

  // Safe getter with fallback
  const safeGet = (data, index, path) => {
    if (!data[index]) return "-";
    return path.split(".").reduce((obj, key) => (obj ? obj[key] : null), data[index]) ?? "-";
  };

  return (
    <div className="p-6 font-sans">
      <h1 className="text-3xl font-bold mb-6 text-center">Foot Sensor Data Comparison</h1>

      <div className="overflow-auto">
        <table className="min-w-full border border-gray-300 rounded-lg overflow-hidden">
          <thead className="bg-gray-100 text-gray-700">
            <tr>
              <th className="border border-gray-300 p-2">Timestamp</th>
              <th colSpan={4} className="border border-gray-300 p-2">Left Foot</th>
              <th colSpan={4} className="border border-gray-300 p-2">Right Foot</th>
            </tr>
            <tr className="bg-gray-200 text-gray-600 text-sm">
              <th className="border border-gray-300 p-1"></th>
              <th className="border border-gray-300 p-1">Force (N)</th>
              <th className="border border-gray-300 p-1">Accel X</th>
              <th className="border border-gray-300 p-1">Accel Y</th>
              <th className="border border-gray-300 p-1">Accel Z</th>

              <th className="border border-gray-300 p-1">Force (N)</th>
              <th className="border border-gray-300 p-1">Accel X</th>
              <th className="border border-gray-300 p-1">Accel Y</th>
              <th className="border border-gray-300 p-1">Accel Z</th>
            </tr>
          </thead>

          <tbody>
            {[...Array(maxRows)].map((_, i) => {
              const left = leftFootData[i];
              const right = rightFootData[i];
              return (
                <tr key={i} className="text-center even:bg-gray-50">
                  <td className="border border-gray-300 p-2 font-mono text-xs whitespace-nowrap">
                    {left?.timestamp ?? right?.timestamp ?? "-"}
                  </td>

                  {/* Left Foot */}
                  <td className="border border-gray-300 p-2">{left?.force ?? "-"}</td>
                  <td className="border border-gray-300 p-2">{left?.accel?.x?.toFixed(2) ?? "-"}</td>
                  <td className="border border-gray-300 p-2">{left?.accel?.y?.toFixed(2) ?? "-"}</td>
                  <td className="border border-gray-300 p-2">{left?.accel?.z?.toFixed(2) ?? "-"}</td>

                  {/* Right Foot */}
                  <td className="border border-gray-300 p-2">{right?.force ?? "-"}</td>
                  <td className="border border-gray-300 p-2">{right?.accel?.x?.toFixed(2) ?? "-"}</td>
                  <td className="border border-gray-300 p-2">{right?.accel?.y?.toFixed(2) ?? "-"}</td>
                  <td className="border border-gray-300 p-2">{right?.accel?.z?.toFixed(2) ?? "-"}</td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>
    </div>
  );
}

export default App;
